    %%{
    gearTilt = -pi/180*5;
    T_gearTilt = [cos(gearTilt) 0 sin(gearTilt);0 1 0;-sin(gearTilt) 0 cos(gearTilt)];
    gearLength = (vehicle.gear.right_pos(3)-gear.main_w(1))/cos(gearTilt); %total gear length from fuselage attachment to wheel hub
    %Assumption: ratio thigh_length/shin_length is given, total gear length is fixed:
    ratio = 1.2;
    a1 = pi/180*25;      %[rad] Thigh angle, in the suspension plane
    %l1 = sqrt(gearLength^2/(1+1/ratio^2-2/ratio*cos(pi-a1+a2)));
    l1 = roots([1-1/ratio^2,-2*cos(a1)*gearLength,gearLength^2]); %derived from law of cosines
    l1 = l1'*((l1>0).*(l1<gearLength));
    l2 = l1/ratio;
    a2 = -acos((gearLength^2+l2^2-l1^2)/(2*gearLength*l2));      %[rad] Shin angle, in the suspension plane
    a2s= 1.45*a2;      %[rad] knee-shock nut
    L1 = l1 * [sin(a1);0;cos(a1)];
    L2 = l2 * [sin(a2);0;cos(a2)];
    l2s = 0.45*l2;
    L2s = l2s*[sin(a2s);0;cos(a2s)];
    L3 = L1+L2s;
    
    gear.L1 = T_gearTilt * L1;
    gear.L2 = T_gearTilt * L2;
    gear.L2s = T_gearTilt * L2s;
    gear.L3 = T_gearTilt * L3;
    %}
