    %Original
    %the UNDEFORMED SUSPENSION ANGLES, assuming symmetry
    %RIGHT LEG
    a1 = pi/180*(18.0896);      %[rad] Thigh angle, in the suspension plane
    a2= pi/180*(-20.7790);      %[rad] Shin angle, in the suspension plane
    a2s= a2 - pi/180*(19);      %[rad] knee-shock nut
    
    %The three MAIN LG suspension member lengths and VECTORS in BDY
    %SHIN
    l2  = 0.265;
    gear.L2  = l2 *[sin(a2)  0  cos(a2)]';
    l2s = 0.165;
    gear.L2s = l2s*[sin(a2s) 0 cos(a2s)]';
    %THIGH
    l1=0.338;
    gear.L1 = l1*[sin(a1) 0 cos(a1)]';
    %SHOCK
    gear.L3 = gear.L1+gear.L2s;
    % l3=modulo(L3);
    % %The MAIN WHEELS hub positions in body axes
