    % H_left_BDY =A_left_BDY + L1 + L2;
    %}
    
    %{
    %Plot
    for i=1:3
        plotMat(1,i) = gear.L1(i);
        plotMat(2,i) = gear.L1(i)+gear.L2(i);
        plotMat(3,i) = gear.L3(i);
        plotMat(4,i) = 0;
    end
    figure
    grid, hold on
    plot(plotMat(1,1),plotMat(1,3),'*r')
    plot(plotMat(2,1),plotMat(2,3),'*k')
    plot(plotMat(3,1),plotMat(3,3),'*b')
    plot(plotMat(4,1),plotMat(4,3),'*c')
    labels = {'K','H','S','A'};
    text(plotMat(:,1),plotMat(:,3),labels,'VerticalAlignment','bottom','HorizontalAlignment','right')
    xlabel('x')
    ylabel('y')
    axis equal
    view(180,90)
    set(gca, 'XDir','reverse')
    %}
    
