    l4 = vehicle.gear.tail_pos(3)-gear.tail_w(1); %rear leg length
    gear.Tbl = [cos(a4)  0  sin(a4);0  1  0;-sin(a4)  0  cos(a4)]; %LEG to BDY _ N
    gear.L4 = [0 0 l4]';                               %rear leg vector
    
    
